INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (1, 1, '蜜桃四季春', '蜜桃香·四季春韵', '成分：鲜嫩水蜜桃果肉+四季春茶底。工艺：手工捣压桃肉出汁，与冷萃四季春茶汤轻柔混合，保留果肉纤维。一口下去，桃香裹挟茶香，清甜不腻，喝完连呼吸都是春天的味道。', '/static/item/tiny/peach_spring.png', '/static/item/large/peach_spring.png', 16.00, 1, '2026-07-03 23:23:14', '2026-07-08 22:10:55');
INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (2, 1, '雪顶蜜桃', '雪山盖顶·桃味暴击', '成分：蜜桃果泥+四季春茶底+奶油雪顶。工艺：蜜桃果泥、清香四季春茶底与冰块打制成沙冰，顶上挤入绵密动物奶油雪顶。入口是冰爽桃沙，顶上是奶香云朵，双重口感，甜蜜暴击！', '/static/item/tiny/peach_snow.png', '/static/item/large/peach_snow.png', 22.00, 1, '2026-07-03 23:23:14', '2026-07-08 22:10:55');
INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (3, 1, '桃李冰冰', '桃李相逢·透心冰爽', '成分：油桃+李子+绿茶。工艺：将桃李鲜果切块急冻，与绿茶汤一同搅打至冰沙状，果酸与茶涩完美平衡。酷暑来一杯，瞬间降温，酸酸甜甜就是夏天的本命。', '/static/item/tiny/peach_lizi.png', '/static/item/large/peach_lizi.png', 15.00, 1, '2026-07-03 23:23:14', '2026-07-08 22:10:55');
INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (4, 1, '车厘子乌龙', '车厘自由·乌龙微醺', '成分：进口车厘子果肉+高山乌龙茶。工艺：车厘子去核捣碎，低温冷泡乌龙茶12小时，融合后滤出清澈酒红液体。果香馥郁，茶韵悠长，喝出高级感，拍照发圈必备。', null, null, 18.00, 1, '2026-07-03 23:23:14', '2026-07-06 01:04:59');
INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (5, 1, '冰椰荔枝', '椰林荔影·一秒海岛', '成分：椰乳+荔枝果肉+冻顶乌龙。工艺：荔枝取肉打浆，与椰乳、乌龙茶按黄金比例混合，加冰摇匀。椰香缠绕荔枝甜，茶底收尾，仿佛置身热带海岛，每一口都是度假。', null, null, 19.00, 1, '2026-07-03 23:23:14', '2026-07-03 23:23:14');
INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (6, 1, '杨枝甘露', '芒果椰奶·经典港风', '成分：新鲜芒果+西柚粒+椰奶+西米。工艺：芒果打泥与椰奶调和，加入煮至透亮的西米和手撕西柚粒，层次分明。芒果浓香，西柚解腻，每一勺都是料，好喝到舔杯。', null, null, 20.00, 1, '2026-07-03 23:23:14', '2026-07-03 23:23:14');
INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (7, 2, '茉莉奶绿', '茉莉白花·奶绿柔润', '成分：茉莉绿茶+鲜奶+炼乳。工艺：茉莉绿茶三熏三窨，与鲜奶慢煮融合，加入少量炼乳提香。茶香奶香交织如丝，入口柔滑，余味有淡淡茉莉花香，治愈一切小情绪。', null, null, 14.00, 1, '2026-07-03 23:23:14', '2026-07-03 23:23:14');
INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (8, 2, '轻乳四季春', '轻负担·厚乳香', '成分：四季春茶+轻乳+燕麦奶。工艺：选用低脂轻乳搭配燕麦奶，与四季春茶汤高速搅打产生绵密泡沫。茶味突出，奶味轻盈，好喝不怕胖，健身党也能放心炫。', null, null, 16.00, 1, '2026-07-03 23:23:14', '2026-07-03 23:23:14');
INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (9, 2, '港式奶茶', '正宗丝滑·港味十足', '成分：锡兰红茶+黑白淡奶。工艺：茶汤反复拉茶8次，撞入热淡奶，茶奶交融。入口先苦后甜，茶味浓烈，奶香醇厚，就是茶餐厅那个味，一秒魂穿香港。', null, null, 13.00, 1, '2026-07-03 23:23:14', '2026-07-03 23:23:14');
INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (10, 2, '港式椰果奶茶', '椰果Q弹·经典加料', '成分：港式奶茶底+脆爽椰果。工艺：在正宗港奶基础上，加入大块热带椰果，手工熬煮糖渍。吸一口，奶茶醇滑，椰果脆蹦蹦，嚼着喝更过瘾，童年回忆杀。', null, null, 15.00, 1, '2026-07-03 23:23:14', '2026-07-03 23:23:14');
INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (11, 3, '万里红茶', '万里茶香·醇厚回甘', '成分：云南大叶种红茶。工艺：传统工夫红茶工艺，揉捻发酵后烘焙，热水冲泡，汤色红艳明亮。入口醇和，蜜糖香突出，回甘持久，适合静心细品。', null, null, 10.00, 1, '2026-07-03 23:23:14', '2026-07-03 23:23:14');
INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (12, 3, '新芽绿茶', '头采新芽·鲜爽至极', '成分：明前绿茶嫩芽。工艺：采摘一芽一叶，高温杀青，轻揉理条，80℃水冲泡。茶汤嫩绿，栗香扑鼻，滋味鲜爽生津，仿佛喝下一整个春天。', null, null, 11.00, 1, '2026-07-03 23:23:14', '2026-07-03 23:23:14');
INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (13, 3, '旧忆乌龙', '老茶韵味·岁月沉香', '成分：陈年乌龙茶。工艺：精选五年陈乌龙，文火慢焙，激发陈香。汤色橙黄，入口顺滑，带有淡淡的果酸和木质香，回味悠长，有故事的味道。', null, null, 12.00, 1, '2026-07-03 23:23:14', '2026-07-03 23:23:14');
INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (14, 4, '四季春奶油卷', '茶香蛋糕·奶油绵密', '成分：四季春茶粉蛋糕胚+动物奶油。工艺：蛋糕体加入四季春茶粉，烤制后卷入打发轻盈的奶油，冷藏定型。茶香与奶香层层交织，松软湿润，甜而不腻，配茶绝佳。', null, null, 18.00, 1, '2026-07-03 23:23:14', '2026-07-03 23:23:14');
INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (15, 4, '红豆奶油卷', '蜜豆绵软·经典搭配', '成分：原味蛋糕胚+蜜红豆+奶油。工艺：蛋糕涂抹奶油，铺满自制蜜红豆，卷紧冷藏。红豆沙绵密，奶油顺滑，每一口都能嚼到红豆粒，日式甜品店的治愈感。', null, null, 17.00, 1, '2026-07-03 23:23:14', '2026-07-03 23:23:14');
INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (16, 4, '臻巧奶油卷', '双重巧克力·浓郁暴击', '成分：巧克力蛋糕胚+巧克力奶油+可可脆珠。工艺：蛋糕胚掺入可可粉，奶油中混入黑巧克力酱，表面撒可可脆珠。巧克力味浓郁到炸，苦甜平衡，巧克力控绝对沦陷。', null, null, 20.00, 1, '2026-07-03 23:23:14', '2026-07-03 23:23:14');
INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (17, 4, '回味老饼干', '儿时记忆·酥脆掉渣', '成分：面粉、黄油、糖、鸡蛋。工艺：传统手工揉面，压模成型，低温慢烤至金黄。奶香四溢，口感酥松，咬一口就想起小时候外婆的铁皮饼干盒，简单却回味无穷。', null, null, 12.00, 1, '2026-07-03 23:23:14', '2026-07-03 23:23:14');
INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (18, 4, '臻巧饼干', '坚果巧克力·越嚼越香', '成分：可可粉、黄油、黑巧克力碎、核桃仁。工艺：面团混入大量黑巧碎和烘烤核桃，切片烘烤。外层酥脆，内里巧克力爆浆，坚果香与巧克力完美融合，下午茶续命神器。', null, null, 14.00, 1, '2026-07-03 23:23:14', '2026-07-03 23:23:14');
INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (19, 5, '南北绿豆茶', '绿豆消暑·南北皆宜', '成分：绿豆+陈皮+海带（咸口）/ 绿豆+百合+冰糖（甜口）。工艺：绿豆慢熬出沙，加入辅料，冰镇后饮用。清凉解暑，沙沙的口感带着陈皮的甘香（或百合的清甜），南北方口味都能驾驭。', null, null, 13.00, 1, '2026-07-03 23:23:14', '2026-07-03 23:23:14');
INSERT INTO tea_and_snow_db.tea_items (id, category_id, name, short_desc, full_desc, small_image_url, large_image_url, base_price, is_active, created_at, updated_at) VALUES (20, 5, '糯米椰子冰', '糯叽叽·椰香冰沙', '成分：椰奶+糯米+椰蓉。工艺：糯米蒸熟打黏，与椰奶冰沙混合，顶部撒烤椰蓉。糯米的软糯与冰沙的冰爽碰撞，椰香四溢，口感奇特又上头，猎奇党必试。', null, null, 16.00, 1, '2026-07-03 23:23:14', '2026-07-03 23:23:14');
